#include <stdio.h>
#include <stdlib.h>
#include <string.h>

const int MOD = 1000000007;

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char X[100005];
    while (T--) {
        scanf("%s", X);
        int n = strlen(X);
        long long *dp = (long long *)malloc((n + 1) * sizeof(long long));
        dp[0] = 1;
        for (int i = 1; i <= n; ++i) {
            dp[i] = 0;
            if (X[i-1] != '0') {
                dp[i] = (dp[i] + dp[i-1]) % MOD;
            }
            if (i >= 2) {
                int val = (X[i-2] - '0') * 10 + (X[i-1] - '0');
                if (val >= 10 && val <= 26) {
                    dp[i] = (dp[i] + dp[i-2]) % MOD;
                }
            }
        }
        printf("%lld\n", dp[n]);
        free(dp);
    }
    return 0;
}

