        for (int t = 0; t < T; t++) {
            String X = br.readLine().trim();
            int n = X.length();
            long[] dp = new long[n+1];
            dp[0] = 1;
            for (int i = 1; i <= n; i++) {
                if (X.charAt(i-1) != '0') {
                    dp[i] = (dp[i] + dp[i-1]) % MOD;
                }
                if (i >= 2) {
                    int val = (X.charAt(i-2)-'0')*10 + (X.charAt(i-1)-'0');
                    if (val >= 10 && val <= 26) {
                        dp[i] = (dp[i] + dp[i-2]) % MOD;
                    }
                }
            }
            sb.append(dp[n]).append('\n');
        }
        System.out.print(sb.toString());
