import sys
MOD = 1_000_000_007

def calculateRSA(X: str) -> int:
    n = len(X)
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, n + 1):
        if X[i-1] != '0':
            dp[i] = (dp[i] + dp[i-1]) % MOD
        if i >= 2:
            two = int(X[i-2:i])
            if 10 <= two <= 26:
                dp[i] = (dp[i] + dp[i-2]) % MOD
    return dp[n]

if __name__ == "__main__":
    data = sys.stdin.read().strip().split()  # first token T then strings
    if not data:
        sys.exit(0)
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        out.append(str(calculateRSA(data[idx])))
        idx += 1
    sys.stdout.write("\n".join(out))

