const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const X = input[pos++];
  const n = X.length;
  const dp = new Array(n + 1).fill(0n);
  dp[0] = 1n;
  for (let i = 1; i <= n; i++) {
    if (X[i - 1] !== '0') {
      dp[i] = (dp[i] + dp[i - 1]) % MOD;
    }
    if (i >= 2) {
      const two = Number(X.slice(i - 2, i));
      if (X[i - 2] !== '0' && two >= 10 && two <= 26) {
        dp[i] = (dp[i] + dp[i - 2]) % MOD;
      }
    }
  }
  results.push(String(dp[n]));
}
